package com.example.oauthclient;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpHeaders;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.util.UriComponentsBuilder;

import java.net.URI;

@SpringBootApplication
public class OAuthClientApplication {
    public static void main(String[] args) {
        SpringApplication.run(OAuthClientApplication.class, args);
    }
}

@Controller
class OAuthController {

    private static final String AUTHORIZATION_ENDPOINT = "https://authorization-server.example.com/oauth/authorize";
    private static final String CLIENT_ID = "your-client-id";
    private static final String REDIRECT_URI = "http://localhost:8080/callback";
    private static final String SCOPE = "read write";
    private static final String RESPONSE_TYPE = "code";

    @GetMapping("/login")
    public ResponseEntity<Void> login() {
        URI authorizationUri = UriComponentsBuilder
                .fromUriString(AUTHORIZATION_ENDPOINT)
                .queryParam("client_id", CLIENT_ID)
                .queryParam("redirect_uri", REDIRECT_URI)
                .queryParam("scope", SCOPE)
                .queryParam("response_type", RESPONSE_TYPE)
                .build()
                .encode()
                .toUri();

        return ResponseEntity
                .status(302)
                .header(HttpHeaders.LOCATION, authorizationUri.toString())
                .build();
    }

    @GetMapping("/callback")
    public ResponseEntity<String> callback() {
        return ResponseEntity.ok("Authorization callback received.");
    }
}